  end 
  end else begin:SR 
  if (AsyncSet) begin:AS 
  always @ (posedge Clock or posedge Set) begin 
  if (Reset) Out <= ResetValue; 
  else if (Set) Out <= SetValue; 
  else if (Enable) Out <= In; 
  end 
  end else begin:SS 
  always @ (posedge Clock) begin 
