      3'b101: begin
        compute_input_tm_cnt = 2;
      end  // 3'b101 

      3'b110: begin
        compute_input_tm_cnt = 2;
      end  // 3'b110 

      3'b111: begin
        compute_input_tm_cnt = 3;
      end  // 3'b111 

