        inhibitFull <= limitHit;
      end
      if (io_clear) begin
        inhibitFull <= 1'b0;
      end
    end
  end

  always @(posedge toplevel_io_axiClk) begin
    if (io_tick) begin
      counter <= (counter + _zz_2_);
    end
    if (io_clear) begin
      counter <= (16'b0000000000000000);
    end
  end

endmodule

