    input J, K, C;
    output reg Q;
    output NQ;

    initial Q = 1'b0;

    always @(posedge C) begin
        case ({J, K})
            2'b10: Q <= 1'b1;
            2'b01: Q <= 1'b0;
            2'b11: Q <= ~Q;
        endcase
    end

