    end
endmodule

module max_system(
    input [3:0] a,
    input [3:0] b,
    output [3:0] max_out
);
    wire equal, greater, less;

    comparator comp (
        .a(a),
        .b(b),
        .equal(equal),
        .greater(greater),
        .less(less)
    );

    max_selector selector (
        .a(a),
        .b(b),
        .equal(equal),
        .greater(greater),
        .less(less),
        .max(max_out)
    );
endmodule

