always @(posedge clk or posedge reset) 
  begin 
  if (reset) reg0 <= 0; 
  else if (write && (address == 4'd0)) reg0 <= writedata; 
  end 
  reg [31:0]pulse1; 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset) 
  begin 
  pulse1 <= 0; 
