  end 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset) reg5 <= 0; 
  else if (write && (address == 4'd5)) reg5 <= writedata; 
  end 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset) reg6 <= 0; 
  else if (write && (address == 4'd6)) reg6 <= writedata; 
  end 
 endmodule

