module rtlpp_02628(
    clk,
    dclk,
    rst,
    display_sel,
    sel,
    data,
    D1,
    D2,
    D3,
    D4
);
    input            clk;
    input            dclk;
    input            rst;
    input            display_sel;
    input [1:0]      sel;
    input [15:0]     data;
    output [3:0]     D1;
    output [3:0]     D2;
    output [3:0]     D3;
    output [3:0]     D4;

    wire [15:0]      bcd_buf;
    wire [19:0]      temp;
    wire [15:0]      unsigned_data;
    wire [19:0]      unsigned_scaled_data;
    wire [15:0]      bcd;

    assign D1 = (display_sel == 1'b1) ? bcd[15:12] : 4'b0000;
    assign D2 = (display_sel == 1'b1) ? bcd[11:8] : data[15:12];
    assign D3 = (display_sel == 1'b1) ? bcd[7:4] : data[11:8];
    assign D4 = (display_sel == 1'b1) ? bcd[3:0] : data[7:4];

    assign bcd[15:12] = ((data[15] == 1'b1 & (bcd[11:0] != 0))) ? 4'b1111 : 4'b1010;

    assign unsigned_data = (data[15] == 1'b1) ? ((~(data)) + 1'b1) : data;

    assign temp = (sel != 2'b11) ? (unsigned_data * 4'b1001) : {4'b0000, (5'd25 - (data - 5'd25))};
    assign unsigned_scaled_data = (sel != 2'b11) ? {10'b0000000000, temp[19:10]} : temp;

    // Embed Binary_To_BCD module functionality into the main module
    reg [3:0] BCDOUT [3:0];
    reg [15:0] BIN;
    reg START;
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            START <= 1'b0;
        end else if (dclk) begin
            START <= ~START;
            BIN <= unsigned_scaled_data[15:0];
        end
    end

    always @(posedge clk) begin
        if (START) begin
            // Perform Binary to BCD conversion
            BCDOUT[0] <= BIN[3:0];
            BCDOUT[1] <= BIN[7:4];
            BCDOUT[2] <= BIN[11:8];
            BCDOUT[3] <= BIN[15:12];
        end
    end

    assign bcd_buf = {BCDOUT[3], BCDOUT[2], BCDOUT[1], BCDOUT[0]};

    assign bcd[11:0] = (sel == 2'b11) ? {bcd_buf[7:0], 4'b1011} : bcd_buf[11:0];

endmodule

