module rtlpp_01795(
                 input wire           clk,
                 input wire           reset_n,

                 input wire [31 : 0]  a,
                 input wire [31 : 0]  b,
                 input wire [31 : 0]  c,
                 input wire [31 : 0]  d,

                 output wire [31 : 0] a_prim,
                 output wire [31 : 0] b_prim,
                 output wire [31 : 0] c_prim,
                 output wire [31 : 0] d_prim
                );

  reg [31 : 0] a0_reg;
  reg [31 : 0] a0_new;
  reg [31 : 0] a1_reg;
  reg [31 : 0] a1_new;
  reg [31 : 0] c0_reg;
  reg [31 : 0] c0_new;

  reg [31 : 0] internal_a_prim;
  reg [31 : 0] internal_b_prim;
  reg [31 : 0] internal_c_prim;
  reg [31 : 0] internal_d_prim;

  assign a_prim = internal_a_prim;
  assign b_prim = internal_b_prim;
  assign c_prim = internal_c_prim;
  assign d_prim = internal_d_prim;

  always @ (posedge clk) begin
    if (!reset_n) begin
      a0_reg <= 32'h0;
      a1_reg <= 32'h0;
      c0_reg <= 32'h0;
    end else begin
      a0_reg <= a0_new;
      a1_reg <= a1_new;
      c0_reg <= c0_new;
    end
  end 

  always @* begin
    reg [31 : 0] a0;
    reg [31 : 0] a1;

    reg [31 : 0] b0;
    reg [31 : 0] b1;
    reg [31 : 0] b2;
    reg [31 : 0] b3;

    reg [31 : 0] c0;
    reg [31 : 0] c1;

    reg [31 : 0] d0;
    reg [31 : 0] d1;
    reg [31 : 0] d2;
    reg [31 : 0] d3;

    a0 = a + b;
    a0_new = a0;

    d0 = d ^ a0_reg;
    d1 = {d0[15 : 0], d0[31 : 16]};

    c0 = c + d1;
    c0_new = c0;

    b0 = b ^ c0_reg;
    b1 = {b0[19 : 0], b0[31 : 20]};

    a1 = a0_reg + b1;
    a1_new = a1;

    d2 = d1 ^ a1_reg;
