      else if (clk_en)
      begin
          if (edge_capture_wr_strobe)
              edge_capture[0] <= 0;
          else if (edge_detect[0])
              edge_capture[0] <= 1;
      end
  end

  always @(posedge clk or negedge reset_n)
  begin
      if (reset_n == 0)
          edge_capture[1] <= 0;
      else if (clk_en)
      begin
          if (edge_capture_wr_strobe)
              edge_capture[1] <= 0;
          else if (edge_detect[1])
              edge_capture[1] <= 1;
      end
  end

  always @(posedge clk or negedge reset_n)
  begin
      if (reset_n == 0)
      begin
          d1_data_in <= 0;
          d2_data_in <= 0;
      end
      else if (clk_en)
      begin
          d1_data_in <= data_in;
          d2_data_in <= d1_data_in;
      end
  end

  assign edge_detect = ~d1_data_in & d2_data_in;

endmodule

