module origen_129227(
    input [7:0] a,
    input [7:0] b,
    input [3:0] priority_input,
    output [7:0] final_output,
    output overflow
);

    wire [15:0] product;
    wire [3:0] priority_encoded;
    wire [3:0] gray_code;
    wire [7:0] multiplication_result;

    // 8-bit multiplication using carry select adder
    carry_select_multiplier csm (
        .a(a),
        .b(b),
        .product(product)
    );

    // Priority encoder
    priority_encoder pe (
        .input_data(priority_input),
        .encoded_output(priority_encoded)
    );

    // Binary to Gray code converter
    binary_to_gray btg (
        .binary_input(priority_encoded),
        .gray_output(gray_code)
    );

    // Final output calculation
    assign multiplication_result = product[7:0];
    assign overflow = product[15] ^ product[14];

    assign final_output = multiplication_result + {4'b0000, priority_encoded};

endmodule

