module origen_125021 #(
    parameter C_S00_AXI_DATA_WIDTH = 32,
    parameter C_S00_AXI_ADDR_WIDTH = 4
) (
    input wire s00_axi_aclk,
    input wire s00_axi_aresetn,
    input wire [C_S00_AXI_ADDR_WIDTH-1:0] s00_axi_awaddr,
    input wire [2:0] s00_axi_awprot,
    input wire s00_axi_awvalid,
    input wire [C_S00_AXI_DATA_WIDTH-1:0] s00_axi_wdata,
    input wire [(C_S00_AXI_DATA_WIDTH/8)-1:0] s00_axi_wstrb,
    input wire s00_axi_wvalid,
    input wire s00_axi_bready,
    input wire [C_S00_AXI_ADDR_WIDTH-1:0] s00_axi_araddr,
    input wire [2:0] s00_axi_arprot,
    input wire s00_axi_arvalid,
    input wire s00_axi_rready,

    output reg pwm_out
);

    // AXI4-Lite signals
    reg [C_S00_AXI_DATA_WIDTH-1:0] axi_rdata;
    reg axi_rvalid;
    reg axi_wready;
    reg axi_awready;
    reg axi_arready;
    reg [1:0] axi_bresp;
    reg axi_bvalid;

    // PWM signals
    reg [6:0] duty_cycle;
    reg [9:0] counter;

    // Clock divider for 1 kHz PWM frequency (assuming 100 MHz input clock)
    reg [15:0] clk_divider;
    wire pwm_clk;

    // AXI write
    always @(posedge s00_axi_aclk) begin
        if (!s00_axi_aresetn) begin
            axi_awready <= 1'b0;
            axi_wready <= 1'b0;
            axi_bvalid <= 1'b0;
            duty_cycle <= 7'd50; // Default 50% duty cycle
        end else begin
            if (~axi_awready && s00_axi_awvalid && s00_axi_wvalid) begin
                axi_awready <= 1'b1;
                axi_wready <= 1'b1;
            end else begin
                axi_awready <= 1'b0;
                axi_wready <= 1'b0;
            end

            if (axi_awready && s00_axi_awvalid && axi_wready && s00_axi_wvalid && ~axi_bvalid) begin
                duty_cycle <= (s00_axi_wdata > 100) ? 7'd100 : s00_axi_wdata[6:0];
                axi_bvalid <= 1'b1;
                axi_bresp <= 2'b00;
            end else if (s00_axi_bready && axi_bvalid) begin
                axi_bvalid <= 1'b0;
            end
        end
    end

    // AXI read (not used in this implementation, but included for completeness)
    always @(posedge s00_axi_aclk) begin
        if (!s00_axi_aresetn) begin
            axi_arready <= 1'b0;
            axi_rvalid <= 1'b0;
            axi_rdata <= 32'd0;
        end else begin
            if (~axi_arready && s00_axi_arvalid) begin
                axi_arready <= 1'b1;
            end else begin
                axi_arready <= 1'b0;
            end

            if (axi_arready && s00_axi_arvalid && ~axi_rvalid) begin
                axi_rvalid <= 1'b1;
                axi_rdata <= {25'b0, duty_cycle};
            end else if (axi_rvalid && s00_axi_rready) begin
                axi_rvalid <= 1'b0;
            end
        end
    end

    // Clock divider for 1 kHz PWM frequency
    always @(posedge s00_axi_aclk) begin
        if (!s00_axi_aresetn) begin
            clk_divider <= 16'd0;
        end else begin
            clk_divider <= clk_divider + 1'b1;
        end
    end

    assign pwm_clk = clk_divider[15];

    // PWM counter
    always @(posedge pwm_clk) begin
        if (!s00_axi_aresetn) begin
            counter <= 10'd0;
        end else begin
            counter <= counter + 1'b1;
        end
    end

    // PWM output
    always @(posedge pwm_clk) begin
        if (!s00_axi_aresetn) begin
            pwm_out <= 1'b0;
        end else begin
            pwm_out <= (counter < {3'b0, duty_cycle}) ? 1'b1 : 1'b0;
        end
    end

endmodule

