	reg clk_div10_3;
	always @(posedge clk_10kHz) begin
		if (count_10_3 == 4) begin
			count_10_3 <= 0;
			clk_div10_3 <= ~clk_div10_3;
		end else begin
			count_10_3 <= count_10_3 + 1;
		end
	end
	assign clk_1kHz = clk_div10_3;

