	reg clk_div10_4;
	always @(posedge clk_1kHz) begin
		if (count_10_4 == 4) begin
			count_10_4 <= 0;
			clk_div10_4 <= ~clk_div10_4;
		end else begin
			count_10_4 <= count_10_4 + 1;
		end
	end
	assign clk_100Hz = clk_div10_4;

	reg [3:0] count_10_5;
	reg clk_div10_5;
	always @(posedge clk_100Hz) begin
		if (count_10_5 == 4) begin
			count_10_5 <= 0;
			clk_div10_5 <= ~clk_div10_5;
		end else begin
			count_10_5 <= count_10_5 + 1;
		end
	end
	assign clk_10Hz = clk_div10_5;

