reg [15:0] omux;        
reg [3:0] zsc;            
reg [7:0] nsc;            

wire s1;
assign s1 = iocs & (ioaddr[2:0] == 1);

always @ (posedge clk)
begin
    if (rst) nsc <= 0;    
    else if (iowr & iocs) nsc <= din[7:0];
    if (rst) zsc <= 0;    
    else if (iowr & iocs) zsc <= din[11:8];
end

always @ (posedge clk)
begin
    if (rst) z <= 0;            
    else if (start) z <= zsc;
    else if (iv & zce) z <= z - 1'b1;
    if (iv) dzce <= zce;        
    if (rst) n <= 0;            
    else if (start) n <= nsc;
    else if (iv & nce) n <= n - 1'b1;
    dnce <= nce;                
end

