begin
    if (rst)
    begin
        state_p0 <= 0;
        state_p1 <= 0;
        state_p2 <= 0;
        state_p3 <= 0;
        state_p4 <= 0;
        state_p5 <= 0;
        state_p6 <= 0;
        state_p7 <= 0;
    end
    else if (iv & ~zce)
    begin
        state_p0 <= phs[1:0];
        state_p1 <= phs[3:2];
        state_p2 <= phs[5:4];
        state_p3 <= phs[7:6];
        state_p4 <= phs[1:0];
        state_p5 <= phs[3:2];
        state_p6 <= phs[5:4];
        state_p7 <= phs[7:6];
    end
end

assign p0 = state_p0;
assign p1 = state_p1;
assign p2 = state_p2;
assign p3 = state_p3;
assign p4 = state_p4;
assign p5 = state_p5;
assign p6 = state_p6;
assign p7 = state_p7;

assign acsv = iv & ~zce;

always @ (posedge clk)
begin
    readsym <= iord & s1;
end

// Embedded tbm1024x8 module functionality
reg [7:0] sym_d0, sym_d1;
reg [9:0] sym_symbols;
reg sym_tbmv;
always @ (posedge clk or posedge rst)
begin
