    begin
        sym_d0 <= 0;
        sym_d1 <= 0;
        sym_symbols <= 0;
        sym_tbmv <= 0;
    end
    else if (acsv)
    begin
        sym_d0 <= {p0, p1, p2, p3};
        sym_d1 <= {p4, p5, p6, p7};
        sym_symbols <= {p0, p1, p2, p3, p4, p5, p6, p7};
