  assign mem_dqs = 2'bz; // High impedance for demonstration
  assign mem_odt = 1'b0;
  assign mem_ras_n = 1'b0;
  assign mem_we_n = 1'b0;
  assign phy_clk = clock_source; // Assuming clock source as PHY clock
  assign reset_phy_clk_n = global_reset_n;
  assign reset_request_n = 1'b1; // Not in reset

  // driver logic
  reg         test_complete_reg;
  reg   [7:0] test_status_reg;
  reg         pnf_reg;
  reg   [7:0] pnf_per_byte_reg;

