                    carryen = 1'b1;
                    sel_mux_mem_alu = 1'b1;
                    sel_mux_inp = 1'b0;
                    output_en = 1'b1;
                    wenout = 1'b1;
                    RegN = 2'b00;
                    RegD = 2'b01;
                    sel_mux_regD = 1'b0;
                    regM = 2'b01;
