module origen_209013 (
    input [31:0] instr,
    input over,
    input Gez,
    output reg [1:0] NPCOp,
    output reg RFWr,
    output reg EXTOp,
    output reg [2:0] ALUOp,
    output reg DMWr,
    output reg [1:0] A3Sel,
    output reg [1:0] WDSel,
