    output reg [25:0] addr26,
    output reg [4:0] rs,
    output reg [4:0] rt,
    output reg [4:0] rd,
    output reg [4:0] A3,
    output reg [1:0] Tuse_rs,
    output reg [1:0] Tuse_rt,
    output reg [1:0] Tnew_E,
    output reg [1:0] Tnew_M
);

    always @(*) begin
        case (instr[31:26])
            6'b000000: begin // R-type
                case (instr[5:0])
