                        imm16 = 16'b0;
                        addr26 = 26'b0;
                        rs = instr[25:21];
                        rt = instr[20:16];
                        rd = instr[15:11];
                        A3 = instr[15:11];
                        Tuse_rs = 2'b01;
                        Tuse_rt = 2'b01;
                        Tnew_E = 2'b10;
                        Tnew_M = 2'b11;
                    end
                    // Add more R-type instructions here
                endcase
            end
            6'b100011: begin // LW
                NPCOp = 2'b00;
                RFWr = 1'b1;
                EXTOp = 1'b1;
                ALUOp = 3'b000;
                DMWr = 1'b0;
                A3Sel = 2'b00;
                WDSel = 2'b01;
                DMSel = 1'b0;
                BSel = 1'b0;
                imm16 = instr[15:0];
                addr26 = 26'b0;
                rs = instr[25:21];
                rt = instr[20:16];
                rd = 5'b0;
                A3 = instr[20:16];
                Tuse_rs = 2'b01;
                Tuse_rt = 2'b11;
                Tnew_E = 2'b10;
                Tnew_M = 2'b11;
            end
            6'b101011: begin // SW
                NPCOp = 2'b00;
                RFWr = 1'b0;
                EXTOp = 1'b1;
                ALUOp = 3'b000;
                DMWr = 1'b1;
                A3Sel = 2'b11;
                WDSel = 2'b10;
                DMSel = 1'b0;
                BSel = 1'b0;
                imm16 = instr[15:0];
                addr26 = 26'b0;
                rs = instr[25:21];
                rt = instr[20:16];
                rd = 5'b0;
                A3 = 5'b0;
                Tuse_rs = 2'b01;
