	if (reset)
		number_packet <= 32'h0;
	else if (write & address == 3'h0)
		number_packet <= writedata;
end

always @ (posedge clk or posedge reset) begin
	if (reset)
		packet_rx_ok <= 32'h0;
	else if (start)
