      .D (p_1_in4_in),
      .Q (exr_lpf),
      .R (1'b0)
  );
  (* XILINX_LEGACY_PRIM = "SRL16" *) (* box_type = "PRIMITIVE" *)
      (* srl_name = "U0/\EXT_LPF/POR_SRL_I " *)
