        if (rx_sop)
            crc32_reg <= 32'hFFFFFFFF;
        if (rx_dval) begin
            crc32_reg <= nextCRC32_D32(rx_data, crc32_reg);
        end
        if (rx_eop) begin
            crcvalid_reg <= 1;
            crcbad_reg <= (crc32_reg != 32'hDEBB20E3); // Assuming 32'hDEBB20E3 is the expected CRC
        end else begin
            crcvalid_reg <= 0;
            crcbad_reg <= 0;
        end
    end
end

function [31:0] nextCRC32_D32;
    input [31:0] Data;
    input [31:0] crc;
    reg [31:0] D;
    reg [31:0] C;
    reg [31:0] NewCRC;
