module autovcoder_096451 (
    sys_clk,
    pwm_in,
    pwm_out
);

  //Parameters
  // 
  parameter COUNTER_SIZE = 10;
  // determined by the input clock frequency (Want divided period to happen about 400 times per millisecond)
  parameter DIVIDER_SIZE = 133;  // to change to 500, 4/5 * 133
  // Number of samples per millisecond
  parameter MAX_COUNT = 400;  // to change to 500, add 100
  parameter LONG_SEQUENCE = 10'b0000000000;  // must must must change to zeros later
  parameter SHORT_SEQUENCE = 10'b0000000000;
  //   inputs
  input wire sys_clk, pwm_in;

  //  output
  output wire [COUNTER_SIZE-1 : 0] pwm_out;

  // internal registers
  reg [COUNTER_SIZE-1 : 0] counter_int;  // internal
  reg [  COUNTER_SIZE : 0] counter_div;  // for dividing clock
  reg [COUNTER_SIZE-1 : 0] out_holder;
  reg                      pwm_h;

  // output has a continuously assigned value
  assign pwm_out = out_holder;

  // all sequential logic for reader in one always block
  always @(posedge sys_clk) begin
    if (~pwm_in) begin
      if (counter_int > MAX_COUNT) begin
        out_holder[COUNTER_SIZE-1 : 0] <= (counter_int[COUNTER_SIZE-1 : 0] - MAX_COUNT);
        counter_int <= SHORT_SEQUENCE;
      end else begin
        counter_int <= SHORT_SEQUENCE;
      end
    end else begin
      out_holder <= out_holder;
    end

    if (pwm_in && (counter_div == 0)) begin
      counter_int <= counter_int + 1;
      counter_div <= DIVIDER_SIZE;
    end else begin
      counter_div <= counter_div - 1;
    end
  end
endmodule

files.autovcoder_067823.v:
module autovcoder_067823 (
      input clk_i
    , input rst_i
    , input speaker_i

    , output mclk_o
    , output bclk_o
    , output lrc_o
    , output sda_o
);

  // We'll use 48 Khz so our sample rate is MCLK / 256

  reg [15:0] next_sample;
  reg [15:0] this_sample;
  reg [ 8:0] clk_div;

  // clk_div[0] = 12.288 MHz
  // clk_div[1] =  6.144 MHz
  // clk_div[2] =  3.072 MHz
  // clk_div[3] =  1.536 MHz
  // clk_div[4] =    768 KHz
  // clk_div[5] =    384 KHz
  // clk_div[6] =    192 KHz
  // clk_div[7] =     96 KHz
  // clk_div[8] =     48 KHz

  assign mclk_o = ~clk_div[0];  // 12.288 MHz
  assign bclk_o = ~clk_div[2];  //  3.072 MHz
  assign lrc_o  = clk_div[8:3] == 6'b0;  // 48.000 KHz
  assign sda_o  = this_sample[~clk_div[6:3]];

  reg last_speaker = 1'b0;
  reg [15:0] timeout = 16'd0;

  always @(posedge clk_i) begin
    if (rst_i) begin
      clk_div <= 0;
    end else begin
      if (speaker_i != last_speaker) begin
        next_sample <= next_sample ? 16'h0000 : 16'h3fff;
        timeout <= 16'hffff;
        last_speaker <= speaker_i;
      end

      clk_div <= clk_div + 1;

      if (clk_div[7:0] == 8'hff) begin
        this_sample <= next_sample;
        if (timeout == 16'h1) next_sample <= 16'h0;
        if (timeout != 16'b0) timeout <= timeout - 1;
      end
    end
  end

endmodule

