module origen_039569 (
    input wire reset,
    input wire enable,
    input wire clock,
    input wire [7:0] in_numberIn,
    output reg switchSample,
    output reg pwmWave
);

    parameter COUNTER_DELAY = 8'd221;

    reg [7:0] accumulator;
    reg [7:0] lastAudioSample;
    reg [7:0] slowerCounter;

    always @(posedge clock) begin
        if (reset) begin
            accumulator <= 8'd0;
            lastAudioSample <= 8'd0;
            slowerCounter <= 8'd0;
            switchSample <= 1'b0;
            pwmWave <= 1'b0;
        end
        else if (enable) begin
            if (slowerCounter == COUNTER_DELAY) begin
                if (accumulator == 8'd0) begin
                    lastAudioSample <= in_numberIn;
                    pwmWave <= (in_numberIn != 8'd0);
                    accumulator <= accumulator + 8'd1;
                    switchSample <= 1'b0;
                end
                else begin
                    accumulator <= accumulator + 8'd1;
                    pwmWave <= (accumulator < lastAudioSample);
                    switchSample <= (accumulator < 8'd128);
                end
                slowerCounter <= 8'd0;
            end
            else begin
                slowerCounter <= slowerCounter + 8'd1;
            end
        end
        else begin
            accumulator <= 8'd0;
            lastAudioSample <= 8'd0;
            slowerCounter <= 8'd0;
            switchSample <= 1'b0;
            pwmWave <= 1'b0;
        end
    end

endmodule

files.autovcoder_000712.v:
module autovcoder_000712 (
    input  clk,
    input  in,
    input  reset,  // Synchronous reset
    output done
);

  parameter Idle = 2'b00;
  parameter Start = 2'b01;
  parameter Data = 2'b10;
  parameter Done = 2'b11;

  reg [1:0] state;
  reg [1:0] next_state;
  reg [3:0] i;
  reg in_last;


  // sequential logic reset
  always @(posedge clk) begin
    if (reset) state <= Idle;
    else state <= next_state;

    // control i
    case (state)
      Idle: i <= 4'b0000;
      Start: i <= 4'b0000;
      Data: i <= i + 4'b0001;
      Done: i <= 4'b0000;
      default: i <= 4'b0000;
    endcase

    in_last <= in;
  end

  // combinational state transition logic
  always @(*) begin
    case (state)
      Idle:
      if ((in == 1'b0) && (in_last == 1'b1)) next_state = Start;
      else next_state = Idle;
      Start: next_state = Data;
      Data:
      if (i <= 4'b0110) next_state = Data;
      else if ((in == 1'b1) && (in_last == 1'b0)) next_state = Done;
      else next_state = Idle;
      Done:
      if ((in == 1'b0) && (in_last == 1'b1)) next_state = Start;
      else next_state = Idle;
      default: next_state = 2'bx;
    endcase
  end

  // combinational logic output
  assign done = (state == Done) ? 1'b1 : 1'b0;

endmodule

