    integer i;
    always @(posedge clk or negedge rst_b) begin
        if (!rst_b) begin
            for (i = 0; i < 15; i = i + 1) begin
                mem[i] <= 32'b0;
            end
            mem[15] <= text_start;
            cpsr <= 32'b0;
        end else begin
            if (rd_we && rd_num != 4'b1111) begin
                mem[rd_num] <= rd_data;
            end
            if (pc_we) begin
                mem[15] <= pc_in;
            end
            if (cpsr_we) begin
                cpsr <= cpsr_in;
