module origen_038685(
    input CLK,
    input [11:0] displayed_number,
    output reg [3:0] an,
    output reg [6:0] seg
);

    reg [3:0] LED_BCD;
    reg [20:0] refresh_counter;
    wire [1:0] LED_activating_counter;

    always @(posedge CLK)
        refresh_counter <= refresh_counter + 1;

    assign LED_activating_counter = refresh_counter[20:19];

    always @(*)
    begin
        case(LED_activating_counter)
        2'b00: begin
            an = 4'b1110;
            LED_BCD = displayed_number % 10;
        end
        2'b01: begin
            an = 4'b1101;
            LED_BCD = (displayed_number / 10) % 10;
        end
        2'b10: begin
            an = 4'b1011;
            LED_BCD = (displayed_number / 100) % 10;
        end
        2'b11: begin
            an = 4'b0111;
            LED_BCD = displayed_number / 1000;
        end
        endcase
    end

    always @(*)
    begin
        case(LED_BCD)
        4'b0000: seg = 7'b0000001; // "0"     
        4'b0001: seg = 7'b1001111; // "1" 
        4'b0010: seg = 7'b0010010; // "2" 
        4'b0011: seg = 7'b0000110; // "3" 
        4'b0100: seg = 7'b1001100; // "4" 
        4'b0101: seg = 7'b0100100; // "5" 
        4'b0110: seg = 7'b0100000; // "6" 
        4'b0111: seg = 7'b0001111; // "7" 
        4'b1000: seg = 7'b0000000; // "8"     
        4'b1001: seg = 7'b0000100; // "9"
        default: seg = 7'b1111111; // Display nothing
        endcase
    end

endmodule

