module origen_033256(
    input wire clk,
    input wire reset,
    output wire [3:0] q
);

    wire [3:0] t_clk;
    assign t_clk[0] = clk;

    genvar i;
    generate
        for (i = 0; i < 4; i = i + 1) begin : tff_gen
            t_flip_flop tff (
                .clk(t_clk[i]),
                .reset(reset),
                .q(q[i])
            );
