module t_flip_flop(
    input wire clk,
    input wire reset,
    output wire q
);

    wire d;
    assign d = ~q;

    d_flip_flop dff (
        .d(d),
        .clk(clk),
        .reset(reset),
        .q(q)
    );

endmodule

