module origen_137080(
    input wire clk,
    input wire reset,
    input wire rd,
    input wire wr,
    input wire [12:0] addr,
    inout wire [7:0] data,
    output reg halt
);

// Internal registers
reg [7:0] accumulator;
reg [7:0] temp_reg;
reg [12:0] program_counter;
reg [7:0] instruction_register;
reg [2:0] state;

// State machine states
localparam FETCH = 3'b000;
localparam DECODE = 3'b001;
localparam EXECUTE = 3'b010;
localparam MEMORY_ACCESS = 3'b011;
localparam WRITE_BACK = 3'b100;

// Instruction opcodes
localparam ADD = 4'b0000;
localparam SUB = 4'b0001;
localparam AND = 4'b0010;
localparam OR  = 4'b0011;
localparam XOR = 4'b0100;
localparam LOAD = 4'b0101;
localparam STORE = 4'b0110;
localparam JUMP = 4'b0111;
localparam HALT = 4'b1111;

// Tri-state buffer for data bus
reg [7:0] data_out;
assign data = (wr) ? data_out : 8'bz;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        accumulator <= 8'b0;
        temp_reg <= 8'b0;
        program_counter <= 13'b0;
        instruction_register <= 8'b0;
        state <= FETCH;
        halt <= 1'b0;
    end else begin
        case (state)
            FETCH: begin
                instruction_register <= data;
                program_counter <= program_counter + 1;
                state <= DECODE;
            end
            DECODE: begin
                case (instruction_register[7:4])
                    ADD, SUB, AND, OR, XOR: state <= EXECUTE;
                    LOAD, STORE: state <= MEMORY_ACCESS;
                    JUMP: begin
                        program_counter <= instruction_register[3:0] & addr[12:4];
                        state <= FETCH;
                    end
                    HALT: begin
                        halt <= 1'b1;
                        state <= FETCH;
                    end
                    default: state <= FETCH;
                endcase
            end
            EXECUTE: begin
                case (instruction_register[7:4])
                    ADD: accumulator <= accumulator + temp_reg;
                    SUB: accumulator <= accumulator - temp_reg;
                    AND: accumulator <= accumulator & temp_reg;
                    OR:  accumulator <= accumulator | temp_reg;
                    XOR: accumulator <= accumulator ^ temp_reg;
                endcase
                state <= WRITE_BACK;
            end
            MEMORY_ACCESS: begin
                if (instruction_register[7:4] == LOAD) begin
                    accumulator <= data;
                end else if (instruction_register[7:4] == STORE) begin
                    data_out <= accumulator;
                end
                state <= WRITE_BACK;
            end
            WRITE_BACK: begin
                state <= FETCH;
            end
        endcase
    end
end

endmodule

