module autovcoder_112744 (
    output reg [3:0] fill_level,

    // Interface: clock
    input              clk,
    input              reset_n,
    // Interface: data_in
    output reg         in_ready,
    input              in_valid,
    input      [132:0] in_data,
    // Interface: data_out
    input              out_ready,
    output reg         out_valid,
    output reg [132:0] out_data
);

  // ---------------------------------------------------------------------
  //| Internal Parameters
  // ---------------------------------------------------------------------
  parameter DEPTH = 8;
  parameter DATA_WIDTH = 133;
  parameter ADDR_WIDTH = 3;

  // ---------------------------------------------------------------------
  //| Signals
  // ---------------------------------------------------------------------
  reg [ADDR_WIDTH-1:0] wr_addr;
  reg [ADDR_WIDTH-1:0] rd_addr;
  reg [ADDR_WIDTH-1:0] next_wr_addr;
  reg [ADDR_WIDTH-1:0] next_rd_addr;
  reg [ADDR_WIDTH-1:0] mem_rd_addr;
  reg [DATA_WIDTH-1:0] mem[DEPTH-1:0];
  reg    empty;
  reg    full;
  reg [0:0] out_ready_vector;

  // ---------------------------------------------------------------------
  //| FIFO Status
  // ---------------------------------------------------------------------
  always @* begin
    //      out_valid = !empty;
    out_ready_vector[0] = out_ready;
    in_ready = !full;
    next_wr_addr = wr_addr + 1'b1;
    next_rd_addr = rd_addr + 1'b1;
    fill_level[ADDR_WIDTH-1:0] = wr_addr - rd_addr;
    fill_level[ADDR_WIDTH] = 0;
    if (full) fill_level = DEPTH[ADDR_WIDTH:0];
  end

  // ---------------------------------------------------------------------
  //| Manage Pointers
  // ---------------------------------------------------------------------
  always @(negedge reset_n, posedge clk) begin
    if (!reset_n) begin
      wr_addr  <= 0;
      rd_addr  <= 0;
      empty    <= 1;
      rd_addr  <= 0;
      full <= 0;
      out_valid <= 0;
    end else begin
      out_valid <= !empty;
      if (in_ready && in_valid) begin
        wr_addr <= next_wr_addr;
        empty   <= 0;
        if (next_wr_addr == rd_addr) full <= 1;
      end

      if (out_ready_vector[0] && out_valid) begin
        rd_addr <= next_rd_addr;
        full    <= 0;
        if (next_rd_addr == wr_addr) begin
          empty <= 1;
          out_valid <= 0;
        end
      end

      if (out_ready_vector[0] && out_valid && in_ready && in_valid) begin
        full  <= full;
        empty <= empty;
      end
    end
  end  // always @ (negedge reset_n, posedge clk)

  always @* begin
    mem_rd_addr = rd_addr;
    if (out_ready && out_valid) begin
      mem_rd_addr = next_rd_addr;
    end
  end


  // ---------------------------------------------------------------------
  //| Infer Memory
  // ---------------------------------------------------------------------
  always @(posedge clk) begin
    if (in_ready && in_valid) mem[wr_addr] <= in_data;
    out_data <= mem[mem_rd_addr];
  end

endmodule

files.autovcoder_076636.v:
module autovcoder_076636 (
    data_in,
    data_out,
    clk,
    reset,
    write,
    read,
    clear,
    almost_full,
    full,
    almost_empty,
    empty,
    cnt
);

  parameter DATA_WIDTH = 32;
  parameter DEPTH = 8;
  parameter CNT_WIDTH = 4;

  input clk;
  input reset;
  input write;
  input read;
  input clear;
  input [DATA_WIDTH-1:0] data_in;

  output [DATA_WIDTH-1:0] data_out;
  output almost_full;
  output full;
  output almost_empty;
  output empty;
  output [CNT_WIDTH-1:0] cnt;

`ifdef ETH_FIFO_XILINX
`else
`ifdef ETH_ALTERA_ALTSYNCRAM
`else
  reg [DATA_WIDTH-1:0] fifo     [0:DEPTH-1];
  reg [DATA_WIDTH-1:0] data_out;
`endif
`endif

  reg [CNT_WIDTH-1:0] cnt;
  reg [CNT_WIDTH-2:0] read_pointer;
  reg [CNT_WIDTH-2:0] write_pointer;


  always @(posedge clk or posedge reset) begin
    if (reset) cnt <= 0;
    else if (clear) cnt <= {{(CNT_WIDTH - 1) {1'b0}}, read ^ write};
    else if (read ^ write)
      if (read) cnt <= cnt - 1;
      else cnt <= cnt + 1;
  end


  always @(posedge clk or posedge reset) begin
    if (reset) read_pointer <= 0;
    else if (clear) read_pointer <= {{(CNT_WIDTH - 2) {1'b0}}, read};
    else if (read & ~empty) read_pointer <= read_pointer + 1'b1;
  end

  always @(posedge clk or posedge reset) begin
    if (reset) write_pointer <= 0;
    else if (clear) write_pointer <= {{(CNT_WIDTH - 2) {1'b0}}, write};
    else if (write & ~full) write_pointer <= write_pointer + 1'b1;
  end

  assign empty = ~(|cnt);
  assign almost_empty = cnt == 1;
  assign full = cnt == DEPTH;
  assign almost_full = &cnt[CNT_WIDTH-2:0];



`ifdef ETH_FIFO_XILINX
  xilinx_dist_ram_16x32 fifo (
      .data_out(data_out),
      .we(write & ~full),
      .data_in(data_in),
      .read_address(clear ? {CNT_WIDTH - 1{1'b0}} : read_pointer),
      .write_address(clear ? {CNT_WIDTH - 1{1'b0}} : write_pointer),
      .wclk(clk)
  );
`else  // !ETH_FIFO_XILINX
`ifdef ETH_ALTERA_ALTSYNCRAM
  altera_dpram_16x32 altera_dpram_16x32_inst (
      .data     (data_in),
      .wren     (write & ~full),
      .wraddress(clear ? {CNT_WIDTH - 1{1'b0}} : write_pointer),
      .rdaddress(clear ? {CNT_WIDTH - 1{1'b0}} : read_pointer),
      .clock    (clk),
      .q        (data_out)
  );  //exemplar attribute altera_dpram_16x32_inst NOOPT TRUE
`else  // !ETH_ALTERA_ALTSYNCRAM
  always @(posedge clk) begin
    if (write & clear) fifo[0] <= data_in;
    else if (write & ~full) fifo[write_pointer] <= data_in;
  end


  always @(posedge clk) begin
    if (clear) data_out <= fifo[0];
    else data_out <= fifo[read_pointer];
  end
`endif  // !ETH_ALTERA_ALTSYNCRAM
`endif  // !ETH_FIFO_XILINX


endmodule

