module origen_090460 #(
    parameter C_init_file = "oled_init.mem",
    parameter C_init_size = 256
) (
    input wire clk,
    output reg [6:0] x,
    output reg [7:0] y,
    output reg next_pixel,
    input wire [15:0] color,
    output reg oled_csn,
    output reg oled_clk,
    output reg oled_mosi,
    output reg oled_dc,
    output reg oled_resn
);

    // State machine states
    localparam RESET = 0, INIT = 1, DELAY = 2, DISPLAY = 3;
    reg [1:0] state = RESET;

    // Initialization sequence
    reg [7:0] init_sequence [0:C_init_size-1];
    reg [7:0] init_index = 0;
    initial $readmemh(C_init_file, init_sequence);

    // Counters and flags
    reg [31:0] delay_counter = 0;
    reg [3:0] bit_counter = 0;
    reg [7:0] byte_counter = 0;
    reg init_done = 0;
    reg high_byte = 1;

    always @(posedge clk) begin
        case (state)
            RESET: begin
                oled_resn <= 0;
                oled_csn <= 1;
                oled_dc <= 1;
                if (delay_counter == 1000000) begin // 10ms at 100MHz
                    state <= INIT;
                    oled_resn <= 1;
                    delay_counter <= 0;
                end else begin
                    delay_counter <= delay_counter + 1;
                end
            end

            INIT: begin
                if (init_index < C_init_size) begin
                    if (init_sequence[init_index] == 8'hFF) begin
                        state <= DELAY;
                        delay_counter <= {init_sequence[init_index+1], init_sequence[init_index+2]} * 100000; // ms to clk cycles
                        init_index <= init_index + 3;
                    end else begin
                        oled_dc <= (init_sequence[init_index] == 8'hFE) ? 0 : 1;
                        oled_csn <= 0;
                        oled_mosi <= init_sequence[init_index][7-bit_counter];
                        if (bit_counter == 7) begin
                            bit_counter <= 0;
                            init_index <= init_index + 1;
                        end else begin
                            bit_counter <= bit_counter + 1;
                        end
                        oled_clk <= ~oled_clk;
                    end
                end else begin
                    state <= DISPLAY;
                    init_done <= 1;
                    x <= 0;
                    y <= 0;
                end
            end

            DELAY: begin
                if (delay_counter == 0) begin
                    state <= INIT;
                end else begin
                    delay_counter <= delay_counter - 1;
                end
            end

            DISPLAY: begin
                oled_dc <= 1;
                oled_csn <= 0;
                if (high_byte) begin
                    oled_mosi <= color[15-bit_counter];
                end else begin
                    oled_mosi <= color[7-bit_counter];
                end

                if (bit_counter == 7) begin
                    bit_counter <= 0;
                    if (high_byte) begin
                        high_byte <= 0;
                    end else begin
                        high_byte <= 1;
                        if (x == 127) begin
                            x <= 0;
                            if (y == 159) begin
                                y <= 0;
                            end else begin
                                y <= y + 1;
                            end
                        end else begin
                            x <= x + 1;
                        end
                        next_pixel <= 1;
                    end
                end else begin
                    bit_counter <= bit_counter + 1;
                    next_pixel <= 0;
                end
                oled_clk <= ~oled_clk;
            end
        endcase
    end

endmodule

