module origen_050199 (
    input wire clk,
    input wire reset,
    input wire Ta,
    input wire Tb,
    output reg green_a,
    output reg yellow_a,
    output reg red_a,
    output reg green_b,
    output reg yellow_b,
    output reg red_b
);

    // State encoding
    parameter S0 = 3'b000,
              S1 = 3'b001,
              S2 = 3'b010,
              S3 = 3'b011,
              S4 = 3'b100,
